    /**
     * Checks if the string s contains "011" or "110" as a subsequence.
     * @param {string} str
     * @returns {boolean} True if it contains the forbidden subsequences, false otherwise.
     */
    function containsForbiddenSubsequence(str) {
        const check = (a, b, c) => {
            let countA = 0;
            let countB = 0;
            let foundC = false;

            for (const char of str) {
                if (char === a) {
                    countA++;
                } else if (char === b) {
                    if (countA > 0) {
                        countB++;
                    }
                } else if (char === c) {
                    if (countB > 0) {
                        // Found subsequence a -> b -> c
                        return true;
                    }
                }
            }
            return false;
        };

        // Check for "011"
        if (check('0', '1', '1')) return true;

        // Check for "110"
        if (check('1', '1', '0')) return true;

        return false;
