fn solve(s: String) -> i64 {
    let n = s.len();
    let s_chars: Vec<char> = s.chars().collect();
    let mut min_flips: i64 = (n + 1) as i64; // Initialize with a value greater than max possible flips

    // Case 1: Target 0*1* (Split point k: first k characters are '0', rest are '1')
    // k ranges from 0 (all '1's) to N (all '0's)
