        let mut cost: i64 = 0;
        // First k characters should be '0'
        for i in 0..k {
            if s_chars[i] == '1' {
                cost += 1;
            }
        }
        // Remaining N-k characters should be '1'
        for i in k..n {
            if s_chars[i] == '0' {
                cost += 1;
            }
        }
        if cost < min_flips {
            min_flips = cost;
        }
    }

    // Case 2: Target 1*0* (Split point k: first k characters are '1', rest are '0')
    // k ranges from 0 (all '0's) to N (all '1's)
    for k in 0..=n {
        let mut cost: i64 = 0;
        // First k characters should be '1'
        for i in 0..k {
            if s_chars[i] == '0' {
                cost += 1;
            }
        }
        // Remaining N-k characters should be '0'
        for i in k..n {
            if s_chars[i] == '1' {
                cost += 1;
            }
        }
        if cost < min_flips {
            min_flips = cost;
        }
    }

    min_flips
}
